Base.h<pre><code>#pragma once

#include &lt;string&gt;
#include &lt;iostream&gt;

class Car {

private:
 std::string name= std::string("Unknown"); // set default name
 float fuel{ 0.0f }; // {} to initialier
 float speed{ 0.0f };
 int passenger{ 0 };

public:
 Car();
 Car(std::string name, float amount);
 void fillFuel(float amount);
 void accelerate();
 void breake();
 void addPassenger(int passenger);
 void dashboard();
 ~Car();
};
</code></pre>

Base.cpp<pre><code>#include "Base.h"

Car::Car(){
 dashboard();
}

Car::Car(std::string name, float amount){
 this-&gt;name = name;
 fuel = amount;

 dashboard();

}

void Car::fillFuel(float amount){
 fuel += amount;
}

void Car::accelerate(){
 speed++;
 fuel -= 0.5f;
}

void Car::breake(){
 speed = 0;
 fuel -= 0.5f;
}

void Car::addPassenger(int passenger){
 this-&gt;passenger += passenger;
}

void Car::dashboard(){
 std::cout &lt;&lt; "&lt; ===   DASHBOARD === &gt;\n";
 std::cout &lt;&lt; "Car name: " &lt;&lt; name &lt;&lt; "\n";
 std::cout &lt;&lt; "Car fuel: " &lt;&lt; fuel &lt;&lt; "\n";
 std::cout &lt;&lt; "Car passenger: " &lt;&lt; passenger &lt;&lt; "\n\n";
 std::cout &lt;&lt; "Speed: " &lt;&lt; speed &lt;&lt; "\n";
}

Car::~Car(){}
</code></pre>

